```csharp
public void TraiterPaiement(double montant, string modePaiement, bool simulationTimeout)
{
    if (montant <= 0)
        throw new ArgumentException("Le montant doit être positif");

    if (modePaiement != "Carte" && modePaiement != "MobileMoney" && modePaiement != "PayPal")
        throw new InvalidOperationException("Mode de paiement non supporté");

    try
    {
        if (simulationTimeout)
            throw new TimeoutException("Délai de connexion dépassé");
        // logique normale
    }
    catch (TimeoutException ex)
    {
        throw new PaiementException("Échec du paiement : problème réseau", ex);
    }
}
```
